// All world countries: ISO code, name, capital, lat/lng center
// Flag emoji is auto-generated from the 2-letter ISO code

export interface CountryFlag {
    code: string;   // ISO 3166-1 alpha-2
    name: string;
    capital: string;
    lat: number;
    lng: number;
}

/** Converts a 2-letter ISO country code to a flag emoji */
export function isoToFlag(code: string): string {
    return [...code.toUpperCase()].map(c =>
        String.fromCodePoint(0x1F1E6 + c.charCodeAt(0) - 65)
    ).join('');
}

